   572→ber_tag_t
   573→ber_get_stringa( BerElement *ber, char **buf )
   574→{
   575→	BerValue	bv;
   576→	ber_tag_t	tag;
   577→
   578→	assert( buf != NULL );
   579→
   580→	tag = ber_get_stringbv( ber, &bv, LBER_BV_ALLOC | LBER_BV_STRING );
   581→	*buf = bv.bv_val;
   582→
   583→	return tag;
   584→}
   585→
   586→ber_tag_t
   587→ber_get_stringa_null( BerElement *ber, char **buf )
   588→{
   589→	BerValue	bv;
   590→	ber_tag_t	tag;
   591→
   592→	assert( buf != NULL );
   593→
   594→	tag = ber_get_stringbv_null( ber, &bv, LBER_BV_ALLOC | LBER_BV_STRING );
   595→	*buf = bv.bv_val;
   596→
   597→	return tag;
   598→}
